site_id = #{siteId}, code_grp = #{codeGrp}, grp_nm = #{grpNm}, path_id = #{pathId}, code_grp_desc = #{codeGrpDesc}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
